{
  description = "todo_list Elixir/Phoenix development environment";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
    flake-utils.url = "github:numtide/flake-utils";
  };

  outputs = { self, nixpkgs, flake-utils, ... }@inputs:
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = import nixpkgs {
          inherit system;
        };

        # Elixir/Erlang toolchain
        elixir = pkgs.beam.packages.erlang.elixir;

        # Universal tools (ALWAYS include these)
        universalTools = with pkgs; [
          git
          git-spice
          pre-commit
          nodejs_22
          glow
          just
          jq
        ];

        # Elixir/Phoenix-specific tools
        elixirTools = with pkgs; [
          elixir
          elixir-ls
          # PostgreSQL client for database operations
          postgresql_17
          # Docker for containerized services
          docker
          docker-compose
        ];

        # Platform-specific dependencies
        darwinDeps = with pkgs; pkgs.lib.optionals stdenv.isDarwin [
          darwin.apple_sdk.frameworks.CoreServices
          darwin.apple_sdk.frameworks.CoreFoundation
        ];

        linuxDeps = with pkgs; pkgs.lib.optionals stdenv.isLinux [
          inotify-tools
        ];

      in {
        devShells.default = pkgs.mkShell {
          buildInputs = universalTools
            ++ elixirTools
            ++ darwinDeps
            ++ linuxDeps;

          shellHook = ''
            # Configure git for stacked PR workflow
            git config --local rebase.updateRefs true 2>/dev/null || true

            # Set up Mix and Hex environment variables
            export MIX_HOME="$PWD/.nix-shell/mix"
            export HEX_HOME="$PWD/.nix-shell/hex"
            export MIX_ARCHIVES="$MIX_HOME/archives"
            export MIX_PATH="$MIX_HOME/escripts"

            # Create directories for Mix and Hex
            mkdir -p .nix-shell/mix .nix-shell/hex

            # Add Mix escripts to PATH
            export PATH="$MIX_PATH:$PATH"

            # Install hex and rebar3 if not already installed
            if ! compgen -G ".nix-shell/hex/hex-*.ez" > /dev/null; then
              echo "Installing Hex package manager..."
              mix local.hex --force --if-missing
            fi

            if [ ! -f .nix-shell/mix/rebar3 ]; then
              echo "Installing rebar3..."
              mix local.rebar --force --if-missing
            fi

            # Install Phoenix archive if not already installed
            if ! compgen -G ".nix-shell/mix/archives/phx_new-*.ez" > /dev/null; then
              echo "Installing Phoenix archive..."
              mix archive.install hex phx_new --force
            fi

            echo "todo_list Elixir/Phoenix development environment loaded"
            echo ""
            echo "Elixir version: $(elixir --version | grep Elixir | cut -d' ' -f2)"
            echo "Mix version: $(mix --version | grep Mix | cut -d' ' -f2)"
            echo ""
            echo "PostgreSQL 17 client available"
            echo "Docker and Docker Compose available"
            echo ""
            echo "To start PostgreSQL: docker-compose up -d"
            echo "To create a new Phoenix project: mix phx.new ."
          '';
        };
      }
    );
}
